solution_steps.command:
cat > /etc/nginx/sites-available/devops.local << 'EOF'
server {
    listen 80;
    server_name devops.local;
    root /var/www/html;
    index index.html;
}
EOF

# Добавить в конфиг Nginx:
# listen 443 ssl;
# ssl_certificate /etc/nginx/ssl/devops.crt;
# ssl_certificate_key /etc/nginx/ssl/devops.key;

# Находим строку: worker_processes 1;;
# Удаляем лишнюю точку с запятой
sed -i 's/worker_processes 1;;/worker_processes 1;/' /etc/nginx/nginx.conf
